1948→        override fun onFling(
1949→            e1: MotionEvent?,
1950→            e2: MotionEvent,
1951→            velocityX: Float,
1952→            velocityY: Float
1953→        ): Boolean {
1954→            Timber.d("onFling")
1955→
1956→            // #5741 - A swipe from the top caused delayedHide to be triggered,
1957→            // accepting a gesture and quickly disabling the status bar, which wasn't ideal.
1958→            // it would be lovely to use e1.getEdgeFlags(), but alas, it doesn't work.
1959→            if (e1 != null && isTouchingEdge(e1)) {
1960→                Timber.d("ignoring edge fling")
1961→                return false
1962→            }
1963→
1964→            // Go back to immersive mode if the user had temporarily exited it (and then execute swipe gesture)
1965→            this@AbstractFlashcardViewer.onFling()
1966→            if (e1 != null && gesturesEnabled) {
1967→                try {
1968→                    val dy = e2.y - e1.y
1969→                    val dx = e2.x - e1.x
1970→                    gestureProcessor.onFling(
1971→                        dx,
1972→                        dy,
1973→                        velocityX,
1974→                        velocityY,
1975→                        isSelecting,
1976→                        isXScrolling,
1977→                        isYScrolling
1978→                    )
1979→                } catch (e: Exception) {
1980→                    Timber.e(e, "onFling Exception")
1981→                }
1982→            }
1983→            return false
1984→        }
