1986→        private fun isTouchingEdge(e1: MotionEvent): Boolean {
1987→            val height = touchLayer!!.height
1988→            val width = touchLayer!!.width
1989→            val margin = Companion.NO_GESTURE_BORDER_DIP * resources.displayMetrics.density + 0.5f
1990→            return e1.x < margin || e1.y < margin || height - e1.y < margin || width - e1.x < margin
1991→        }
