2204→    /** Signals from a WebView represent actions with no parameters  */
2205→    @VisibleForTesting
2206→    internal object WebViewSignalParserUtils {
2207→        /** A signal which we did not know how to handle  */
2208→        const val SIGNAL_UNHANDLED = 0
2209→
2210→        /** A known signal which should perform a noop  */
2211→        const val SIGNAL_NOOP = 1
2212→        const val TYPE_FOCUS = 2
2213→
2214→        /** Tell the app that we no longer want to focus the WebView and should instead return keyboard focus to a
2215→         * native answer input method.  */
2216→        const val RELINQUISH_FOCUS = 3
2217→        const val SHOW_ANSWER = 4
2218→        const val ANSWER_ORDINAL_1 = 5
2219→        const val ANSWER_ORDINAL_2 = 6
2220→        const val ANSWER_ORDINAL_3 = 7
2221→        const val ANSWER_ORDINAL_4 = 8
2222→        fun getSignalFromUrl(url: String): Int {
2223→            when (url) {
2224→                "signal:typefocus" -> return TYPE_FOCUS
2225→                "signal:relinquishFocus" -> return RELINQUISH_FOCUS
2226→                "signal:show_answer" -> return SHOW_ANSWER
2227→                "signal:answer_ease1" -> return ANSWER_ORDINAL_1
2228→                "signal:answer_ease2" -> return ANSWER_ORDINAL_2
2229→                "signal:answer_ease3" -> return ANSWER_ORDINAL_3
2230→                "signal:answer_ease4" -> return ANSWER_ORDINAL_4
2231→                else -> {}
2232→            }
2233→            if (url.startsWith("signal:answer_ease")) {
2234→                Timber.w("Unhandled signal: ease value: %s", url)
2235→                return SIGNAL_NOOP
2236→            }
2237→            return SIGNAL_UNHANDLED // unknown, or not a signal.
2238→        }
2239→    }
