2299→        // Filter any links using the custom "playsound" protocol defined in Sound.java.
2300→        // We play sounds through these links when a user taps the sound icon.
2301→        @NeedsTest("integration test with typechangetext")
2302→        fun filterUrl(url: String): Boolean {
2303→            if (url.startsWith("playsound:")) {
2304→                launchCatchingTask {
2305→                    controlSound(url)
2306→                }
2307→                return true
2308→            }
2309→            if (url.startsWith("state-mutation-error:")) {
2310→                onStateMutationError()
2311→                return true
2312→            }
2313→            if (url.startsWith("tts-voices:")) {
2314→                showDialogFragment(TtsVoicesDialogFragment())
2315→                return true
2316→            }
2317→            if (url.startsWith("file") || url.startsWith("data:")) {
2318→                return false // Let the webview load files, i.e. local images.
2319→            }
2320→            if (url.startsWith("typechangetext:")) {
2321→                // Store the text the javascript has sent us…
2322→                typeAnswer!!.input = decodeUrl(url.replaceFirst("typechangetext:".toRegex(), ""))
2323→                return true
2324→            }
2325→            if (url.startsWith("typeentertext:")) {
2326→                // Store the text the javascript has send us…
2327→                typeAnswer!!.input = decodeUrl(url.replaceFirst("typeentertext:".toRegex(), ""))
2328→                // … and show the answer.
2329→                flipCardLayout!!.performClick()
2330→                return true
2331→            }
2332→
2333→            // card.html reload
2334→            if (url.startsWith("signal:reload_card_html")) {
2335→                redrawCard()
2336→                return true
2337→            }
2338→
2339→            when (val signalOrdinal = WebViewSignalParserUtils.getSignalFromUrl(url)) {
2340→                WebViewSignalParserUtils.SIGNAL_UNHANDLED -> {}
2341→                WebViewSignalParserUtils.SIGNAL_NOOP -> return true
2342→                WebViewSignalParserUtils.TYPE_FOCUS -> return true
2343→
2344→                WebViewSignalParserUtils.RELINQUISH_FOCUS -> {
2345→                    // #5811 - The WebView could be focused via mouse. Allow components to return focus to Android.
2346→                    focusAnswerCompletionField()
2347→                    return true
2348→                }
2349→
2350→                WebViewSignalParserUtils.SHOW_ANSWER -> {
2351→                    // display answer when showAnswer() called from card.js
2352→                    if (!Companion.displayAnswer) {
2353→                        displayCardAnswer()
2354→                    }
2355→                    return true
2356→                }
2357→
2358→                WebViewSignalParserUtils.ANSWER_ORDINAL_1 -> {
2359→                    flipOrAnswerCard(EASE_1)
2360→                    return true
2361→                }
2362→
2363→                WebViewSignalParserUtils.ANSWER_ORDINAL_2 -> {
2364→                    flipOrAnswerCard(EASE_2)
2365→                    return true
2366→                }
2367→
2368→                WebViewSignalParserUtils.ANSWER_ORDINAL_3 -> {
2369→                    flipOrAnswerCard(EASE_3)
2370→                    return true
2371→                }
2372→
2373→                WebViewSignalParserUtils.ANSWER_ORDINAL_4 -> {
2374→                    flipOrAnswerCard(EASE_4)
2375→                    return true
2376→                }
2377→
2378→                else -> {
2379→                    // We know it was a signal, but forgot a case in the case statement.
2380→                    // This is not the same as SIGNAL_UNHANDLED, where it isn't a known signal.
2381→                    Timber.w("Unhandled signal case: %d", signalOrdinal)
2382→                    return true
2383→                }
2384→            }
2385→            var intent: Intent? = null
2386→            try {
2387→                if (url.startsWith("intent:")) {
2388→                    intent = Intent.parseUri(url, Intent.URI_INTENT_SCHEME)
2389→                } else if (url.startsWith("android-app:")) {
2390→                    intent = Intent.parseUri(url, Intent.URI_ANDROID_APP_SCHEME)
2391→                }
2392→                if (intent != null) {
2393→                    if (packageManager.resolveActivityCompat(
2394→                            intent,
2395→                            ResolveInfoFlagsCompat.EMPTY
2396→                        ) == null
2397→                    ) {
2398→                        val packageName = intent.getPackage()
2399→                        if (packageName == null) {
2400→                            Timber.d(
2401→                                "Not using resolved intent uri because not available: %s",
2402→                                intent
2403→                            )
2404→                            intent = null
2405→                        } else {
2406→                            Timber.d(
2407→                                "Resolving intent uri to market uri because not available: %s",
2408→                                intent
2409→                            )
2410→                            intent = Intent(
2411→                                Intent.ACTION_VIEW,
2412→                                Uri.parse("market://details?id=$packageName")
2413→                            )
2414→                            if (packageManager.resolveActivityCompat(
2415→                                    intent,
2416→                                    ResolveInfoFlagsCompat.EMPTY
2417→                                ) == null
2418→                            ) {
2419→                                intent = null
2420→                            }
2421→                        }
2422→                    } else {
2423→                        // https://developer.chrome.com/multidevice/android/intents says that we should remove this
2424→                        intent.addCategory(Intent.CATEGORY_BROWSABLE)
2425→                    }
2426→                }
2427→            } catch (t: Throwable) {
2428→                Timber.w("Unable to parse intent uri: %s because: %s", url, t.message)
2429→            }
2430→            if (intent == null) {
2431→                Timber.d("Opening external link \"%s\" with an Intent", url)
2432→                intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
2433→            } else {
2434→                Timber.d("Opening resolved external link \"%s\" with an Intent: %s", url, intent)
2435→            }
2436→            try {
2437→                startActivity(intent)
2438→            } catch (e: ActivityNotFoundException) {
2439→                Timber.w(e) // Don't crash if the intent is not handled
2440→            }
2441→            return true
2442→        }
